mapper.insert:
INSERT INTO CART (
    CART_ID, MEMBER_NO, PRODUCT_ID, CART_QTY
) VALUES (
    SEQ_CART.NEXTVAL, #{memberNo}, #{productId}, #{cartQty}
)

mapper.select:
SELECT c.CART_ID, c.MEMBER_NO, c.PRODUCT_ID, c.CART_QTY, p.PRODUCT_NAME, p.PRODUCT_PRICE, p.PRODUCT_PHOTO1 FROM CART c JOIN PRODUCT p ON c.PRODUCT_ID = p.PRODUCT_ID WHERE c.CART_ID IN
#{id}
AND c.MEMBER_NO = #{memberNo}
